var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"예상은 했지만 조잡한 집이로군.","JPN":"予想はしていたが、粗末な家だな。","ENG":"It is not unexpected, but it is truly a crude house.","TWN":"雖然已經有心理準備，但這房子還真是簡陋。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"산 꼭대기 마을이라더니. 이런 열악한 환경에서 잘도 살아남았어.","JPN":"山の頂上にある村だと聞いたが。このような劣悪な環境でよくも生き延びたものだ。","ENG":"A village atop a mountain. It is a miracle they survived in such harsh conditions.","TWN":"雖說是山頂上的村莊，沒想到竟能在這樣惡劣的環境中生存下來。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"귀하신 분을 이런 누추한 곳에 모시니 송구스럽기 그지없습니다.","JPN":"高貴な方をこのようなむさ苦しいところでおもてなしすることとなり、大変心苦しい限りです。","ENG":"I wish there was somewhere less lacking for our royal guests to stay at. I apologize.","TWN":"實在是非常抱歉，只有這麼簡陋的地方可以招待貴客。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"전하께서 괜찮으시다면 축제를 앞당기는 것도 가능합니다만….","JPN":"殿下さえよろしければ、祭りの時期を早めることもできますが……","ENG":"With your permission, we could hold the festival a bit earlier...","TWN":"若殿下不介意，也要把慶典提前也不是不可以…"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"됐다. 백성을 보호해야 할 황족이 어찌 그들에게 도움을 받을 수 있겠나.","JPN":"いや、いい。民を保護すべき皇族が、逆に助けられるわけにはいかない。","ENG":"Leave it. Royalty is supposed to protect their subjects, not receive assistance from them.","TWN":"沒關係，身為應該保護百姓的皇族，怎能接受他們的幫助呢。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"맞습니다. 평소 호의호식을 누리는 전하께서 설마 이 정도 곤욕도 못 치루시겠습니까.","JPN":"そのとおりです。普段贅沢に暮らしている殿下が、まさかこの程度の困難も耐えられないはずがありません。","ENG":"I agree. His Highness is in clover every other day, so he can stand to put up with a bit of trouble for a couple days.","TWN":"說得對，殿下平時吃好穿好的，這對殿下而言小意思吧？"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당장 궁정에서 나오는 대궁만으로도 이곳 주민들이 배불리 먹을 수 있을 텐데요.","JPN":"今日宮廷から出る残飯だけでも、ここの住民が存分に食べられるはずです。","ENG":"Not to mention that the leftover food from the palace would be more than enough to feed this entire village.","TWN":"光是宮裡的剩菜剩飯就能夠餵飽這裡所有的居民吧。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"이전부터 느낀 것이지만 성녀는 말이 많으시군요.","JPN":"前から思っていたのですが、聖女はおしゃべりですね。","ENG":"I am repeatedly reminded of how verbose you are, Saintess.","TWN":"我從以前就覺得，聖女真是多話。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"긴 혀가 문제라면 제가 조금 도려내 드리겠습니다.","JPN":"長い舌のせいでしたら、少し切り取ってさしあげましょう。","ENG":"If it is your tongue length that's bothering you, I'll gladly trim it.","TWN":"如果長舌頭是個問題，我可以幫你割掉一些。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…알았으니까 칼 좀 집어넣으시죠.","JPN":"……わかりましたから、剣をおさめてください。","ENG":"...Okay, so you can put your sword away.","TWN":"……不用客氣，請收起你的刀。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"둘 다 진정해. 모처럼 촌장님이 권유해 주셨는데 민폐를 끼칠 순 없잖아.","JPN":"二人とも落ち着いて。せっかく村長が誘ってくれたのに、ご迷惑をかけるわけにはいかないでしょう？","ENG":"Calm down, both of you. We can't be a nuisance, not when the chief invited us to stay.","TWN":"二位都冷靜點，難得村長邀請我們，怎麼能給人家添麻煩呢。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"촌장님. 축제에 대해 조금 더 자세히 설명해주실 수 있나요?","JPN":"村長。お祭りについて、もうちょっと詳しく説明してくれませんか？","ENG":"Chief, could you tell us more about this festival?","TWN":"村長，可以再多說一點關於這個慶典的事嗎？"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"이런. 이 늙은이가 깜빡하고 설명도 안 해드렸나 봅니다.","JPN":"おやおや。わしとしたことが、うっかり説明もしていなかったようですな。","ENG":"Oh dear. I must've forgotten to explain further.","TWN":"真是糟糕，看看我這個老糊塗，竟然忘記跟各位介紹一下。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"혹시 구원자님께서는 제국 무도회의 기원이 무엇인지 알고 계십니까?","JPN":"救世主様は帝国の舞踏会の起源についてご存じでしょうか？","ENG":"Do you happen to know how the Imperial Ball first started, Savior?","TWN":"救贖者大人大人，您知道帝國舞會的起源嗎？"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아뇨. 전 시골에서 살아서 무도회는 이번이 처음이거든요.","JPN":"いいえ。僕は田舎育ちなので、舞踏会はこれが初めてです。","ENG":"No. I lived in the countryside, I've never been to a ball before.","TWN":"不太清楚，因為我之前都住在鄉下，這是我第一次參加舞會。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"무도회가 있다는 것도 실은 얼마 전에 처음 알았어요.","JPN":"舞踏会があるってことも、実はこの前初めて知ったんです。","ENG":"I only recently found out that this ball existed.","TWN":"其實有舞會的事我也是前陣子才知道的。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"제국이 생기기 이전, 사람들은 풍작을 위해 풍요의 신께 제사를 올렸다고 전해지지요.","JPN":"帝国の建国前、人々は豊作のために豊穣の神への祭祀を行っていたと伝えられております。","ENG":"It is said that, before the Empire came to be, people used to pray to the god of prosperity for a bountiful harvest.","TWN":"在帝國創立之前，人們會向豐饒之神祭祀祈求豐收。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"몬테는 전통을 이어받아 지금까지도 그 명맥을 이어 나가고 있습니다.","JPN":"モンテは伝統を受け継ぎ、今でもそれを守り続けています。","ENG":"Even after all this time, Monte has been keeping the tradition alive.","TWN":"蒙特延續這個傳統至今，"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"매년 순정한 남녀 한 쌍을 뽑아, 마을의 풍요를 기원하며 신께 제를 올리는 것이지요.","JPN":"毎年、無垢な男女を選抜し、村の豊穣を祈りながら祭祀を行うのです。","ENG":"We select a chaste couple to perform a rite, praying to the gods for the prosperity of the village.","TWN":"每年選出一對純真的男女，向神祈求村莊的豐收。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"풍작을 위한 제사인가. 제법 풍류가 있는 마을이로군.","JPN":"豊作のための祭祀か。なかなか趣のある村だ。","ENG":"A rite for a bountiful harvest. The village upholds more culture than I thought.","TWN":"原來目的是要祈求豐收，很棒的傳統呢。"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"그래서 말인데, 혹여 성녀님이 괜찮으시다면 이번 축제의 제를 부탁드릴 수 있겠습니까?","JPN":"それでなのですが、よろしければ聖女様に今度の祭りの祭祀を司っていただけないでしょうか？","ENG":"And while we are on the subject of the rite, could I ask you to perform it, Saintess?","TWN":"所以，若是聖女不介意，這次的祭祀能否由您來主持？"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"제국의 성녀께서 직접 제를 올린다면 분명 신께서도 기뻐하실 겁니다.","JPN":"帝国の聖女様が直接祭祀を行うとなれば、きっと神もお喜びになられるでしょう。","ENG":"There is no doubt that god would be pleased if the Empire's Saintess performs the rite herself.","TWN":"帝國的聖女親自主持祭祀，神一定會很高興的。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"별 상관은 없습니다만. 제라면 구체적으로 어떤 걸 하는 건가요?","JPN":"別に構いませんが。祭祀というと、具体的に何をするのですか？","ENG":"I do not think it would be impossible. But what would the rite entail?","TWN":"我是無所謂，只是具體而言祭祀要做什麼？"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"그리 어려운 일은 아닙니다.","JPN":"そう難しいことではありません。","ENG":"It's nothing too complicated.","TWN":"不難。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"대대로 내려오는 신의를 입고 상대 남성분과 춤을 춰 주시기만 하면…","JPN":"代々伝えられている神衣を着て、相手方の男性と踊ってくだされば……","ENG":"The rite is performed by a woman in sacred garments dancing with her partner–","TWN":"只需要穿上祖傳的聖衣，與另一位祭祀的男子共舞…"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};